BEGIN TRANSACTION;
INSERT INTO "Movies" ("Id", "Title", "OriginalTitle", "ReleaseYear", "CountryCode", "OriginalLanguage", "Director", "Synopsis", "DurationMinutes", "AgeRating", "CreatedAtUtc", "ExternalId", "Image") VALUES
('c94b42c0-f81a-4af5-a476-c3ed759a4f22', 'A Face Oculta de Varginha: Poder, Dinheiro e Rituais.', 'A Face Oculta de Varginha: Poder, Dinheiro e Rituais.', 2026, 'BR', 'pt', NULL, 'O filme apresenta diferentes visões sobre o caso — ufológica, religiosa e ocultista. Além dos relatos de aparições e da possível captura de criaturas, ele sugere que mortes de animais, movimentação militar e testemunhos estranhos poderiam estar ligados a rituais, forças ocultas ou interesses políticos.  No fim, o documentário trata o episódio como um mistério complexo, onde ETs, ocultismo e manipulação de informações podem estar misturados, sem dar uma conclusão definitiva.  Se quiser, também posso te contar quais partes do documentário são fatos históricos confirmados e quais são mais teoria/conspiração — essa história de Varginha tem muita coisa misturada.', NULL, NULL, CURRENT_TIMESTAMP, 1652717, '/jhemlyhhwpEYRgnWqSPRXXFVWxL.jpg'),
('fe96382f-ad6c-40ad-a4dc-d62868b0703f', 'DADO', 'DADO', 2026, 'BR', 'pt', NULL, 'Em sua lua de mel, Penha e Dado viajam em um Fusca sem se preocupar com o futuro. A viagem toma um rumo estranho quando Penha começa a ouvir transmissões de rádio que revelam o que acontecerá com seu casamento.', NULL, NULL, CURRENT_TIMESTAMP, 1650521, '/mN2reCE5bx9ulqBWv0tyk3TSEXe.jpg'),
('b7b5331a-950a-4085-87c9-433382290cdb', 'Like a Prayer', 'Como uma oração', 2026, 'BR', 'pt', NULL, 'Joana, uma mulher trans, e Carlos, um adolescente se descobrindo gay, vivem no mesmo prédio. O interesse em comum por uma cantora pop nos anos 80, faz com que ambos iniciem uma conversa, mas não passa disso. Anos depois Carlos descobre que Joana está só e passa a visitá-la, o que cria entre eles um laço de afeto e amizade.', NULL, NULL, CURRENT_TIMESTAMP, 1637169, '/xclMw6um2y1dHsWoQQalghQYb71.jpg'),
('f6345d11-cbf8-4e88-83d8-886f257d0182', 'Masterpiece', 'Masterpiece', 2026, 'BR', 'pt', NULL, 'Masterpiece é o longa-metragem de estreia dos diretores Diego Oliveira e Marcelo Lobo, um drama intenso que mergulha nos limites entre arte, obsessão e identidade.', NULL, NULL, CURRENT_TIMESTAMP, 1636462, '/fHjnRimOfzB5Dm2EHcvSbFW8yeZ.jpg'),
('b27b5ea8-569a-415e-967f-e2b2611d3051', 'A Mensagem', 'The Message', 2026, 'BR', 'en', NULL, 'Um menino envia uma mensagem.', NULL, NULL, CURRENT_TIMESTAMP, 1624130, '/g0Dhj3z8DCPRuVwG3K4Et6mSxqf.jpg'),
('86650bb0-2561-4455-9e56-9d852b9c62b2', 'Pescador', 'Pescador', 2026, 'BR', 'pt', NULL, 'Após a morte da esposa, Benedito passa a viver isolado às margens de um rio, sustentado por uma rotina rígida e silenciosa. Incapaz de aceitar a perda, ele mantém uma jovem em cativeiro e tenta projetar nela a presença da mulher que se foi, transformando o afeto em controle. Entre gestos repetidos, rituais domésticos e silêncios opressivos, a relação entre os dois revela a fragilidade de um homem em ruína e a resistência silenciosa de quem luta para sobreviver. À medida que a rotina se rompe, Benedito é confrontado com a impossibilidade de substituir o passado e com a urgência de encarar o próprio vazio. O Pescador é um drama psicológico sobre luto, memória e as consequências de tentar amar através da dominação.', NULL, NULL, CURRENT_TIMESTAMP, 1619561, '/uPDz1gKYPUX4ozJp8VXUtoweTkX.jpg'),
('047f803c-8df0-41e3-a265-31e85aa2c7fc', 'O penúltimo ano', 'O penúltimo ano', 2026, 'BR', 'pt', NULL, 'Uma simples viagem para Angra dos Reis se torna um momento inesquecível para nove jovens estudantes do segundo ano do Ensino Médio.', NULL, NULL, CURRENT_TIMESTAMP, 1607665, '/jj9adEjBYWL5QxHdMly8GENh3ZC.jpg'),
('cda905e2-76e5-49e4-ba32-bf49bcd3f5ea', 'Te Reconheço, Mas Me Parece Estranho', 'Te Reconheço, Mas Me Parece Estranho', 2026, 'BR', 'pt', NULL, 'Dentro de fotos que não são suas, um corpo descobre que sempre foi parte de outro.', NULL, NULL, CURRENT_TIMESTAMP, 1606068, '/nBhCVeh71IHkgM9CPgIwL6oNzEW.jpg'),
('4b2f1139-8746-4e52-a32f-ba05acbd7032', 'Filhos da Cana', 'Filhos da Cana', 2026, 'BR', 'pt', NULL, '', NULL, NULL, CURRENT_TIMESTAMP, 1586920, '/w3K2QHYpriVVdNJQzZFA8Xo5vhw.jpg'),
('c6ee71ae-e09b-4412-8e44-42355ea64f3b', 'Cidade Conquista', 'Cidade Conquista', 2026, 'BR', 'pt', NULL, '', NULL, NULL, CURRENT_TIMESTAMP, 1571233, '/gMEj1BXCwKVfeFWa4xFR6JYHlWX.jpg'),
('e3004a07-2296-4caa-9570-93ceae8d95c4', 'O Ponto da Costura', 'O Ponto da Costura', 2026, 'BR', 'pt', NULL, '', NULL, NULL, CURRENT_TIMESTAMP, 1535860, NULL),
('cb1d9d51-d212-4260-af29-d769b8d60375', 'The last years', 'The last years', 2026, 'BR', 'pt', NULL, 'Um grupo de amigos adolescentes, decidem contar sua história de vida, sobre seus futuros e sobre o medo de se afastarem após acabarem o ensino fundamental e irem ao ensino médio, contando sobre como se conheceram, como passaram todos esses anos unidos independente de cada briga que ocorreu entre eles e sobre antigos integrantes do grupo, tudo isso contado em apenas uma cidade simples do Brazil, uma cidade pequena com pouco menos de 200k de habitantes e com uma educação precária.', NULL, NULL, CURRENT_TIMESTAMP, 1513402, NULL),
('4323823b-41d1-415f-85a6-8c380dfa847a', 'Gato de Botas: A Última Dívida', 'Gato de Botas: A Última Dívida', 2026, 'BR', 'pt', NULL, 'Este é... Gato de Botas, descubra sua origem e veja a consequência de seus atos nesse curta-metragem adaptado.', NULL, NULL, CURRENT_TIMESTAMP, 1610539, '/fdCd1d9tfSt4fITSsOwQx2lnv3p.jpg'),
('58db1258-be73-485b-bf9c-56fd8f03a043', 'Antequam Rogem', 'Antequam Rogem', 2026, 'BR', 'pt', NULL, 'Antequam Rogem se constrói como um pré pedido, o instante que antecede uma decisão irreversível. O filme acompanha o reencontro de alguém que caminhava deslocado, em um mundo sem cor, onde rostos se apagam e o tempo avança e recua como quem hesita.  À medida que a narrativa se desenrola, pequenas fontes de energia atravessam a imagem. Figuras simbólicas surgem, aproximam-se, e aquilo que antes era borrão começa a ganhar contorno. As cicatrizes permanecem visíveis, mas já não sangram.', NULL, NULL, CURRENT_TIMESTAMP, 1610416, '/iDcoWhjrP6p4QVcddoijB5ix1W9.jpg'),
('6fdff10a-6d81-431e-8520-f6d4011cb036', 'Do Alto da serra', 'Do Alto da serra', 2026, 'BR', 'pt', NULL, 'A irmã de Tereza, Eunice, sumiu na Serrinha tentando encontrar a história de Batalha (um sonho de seus falecidos pais). Para trazê-la de volta, Tereza convoca o Lendário e antigo trio de caçadores de lendas do nordeste: Manézinho, Veloso Lindoso e Misturada, que estão separados há décadas.', NULL, NULL, CURRENT_TIMESTAMP, 1608509, '/oePvEh59P2TOOibHm2vpukkPMKf.jpg'),
('4802e720-897b-483a-9b8a-2cd3ee0c74e7', 'Encontro com Darcy (VR)', 'Encontro com Darcy (VR)', 2026, 'BR', 'pt', NULL, 'Yandara é uma jovem indígena urbana em processo de retomada cultural. Sozinha no Memorial dos Povos Indígenas, preparando um protesto que ninguém virá, ela tem um encontro impossível: Darcy Ribeiro (1922-1997), criador do Parque do Xingu e um dos maiores defensores dos povos originários do Brasil, aparece diante dela.  Ao vestir os óculos de realidade virtual você está presente neste diálogo entre gerações que atravessa a natureza e chega ao Salão Negro do Congresso Nacional. Darcy provoca Yandara a fazer uma escolha: resignar-se ou indignar-se. E ela descobre que, como ele - que vestiu muitas "peles" e permaneceu inteiro -, pode ser todas as coisas que é e ainda encontrar sua galera para continuar a luta.', NULL, NULL, CURRENT_TIMESTAMP, 1603519, '/sscByNDrqoYazu0IewNikCERPc2.jpg'),
('0bf463f7-3d97-4cfd-9f86-55a99713d330', 'ainda aqui.', 'ainda aqui.', 2026, 'BR', 'pt', NULL, 'Acompanhe “ainda aqui.”, uma história em VHS do cineasta Marcos Gale sobre Rocco (Christyan McGray), um garoto que caminha entre o silêncio e a memória, atravessando solidão, bullying e introspecção enquanto reflete sobre saúde mental e o simples — e complexo — ato de permanecer.', NULL, NULL, CURRENT_TIMESTAMP, 1610455, '/wJyNM42K9xoFEafNrp5BL7f0Jx5.jpg'),
('e422cead-bfd3-4f9a-ad5a-b36d8bc03845', 'quando chove em um sábado', 'quando chove em um sábado', 2026, 'BR', 'pt', NULL, 'neste curta, a câmera se distrai com diversas texturas e observa seu quarto enquanto aguarda ansiosamente a luz voltar para poder assistir um filme.', NULL, NULL, CURRENT_TIMESTAMP, 1606195, '/aFBM4I58sqMtFHLl2iBi9nUPRbv.jpg'),
('22e3102c-6758-42d2-b9d7-8a441fce55ed', 'Paty', 'Paty', 2026, 'BR', 'pt', NULL, 'Durante o trajeto noturno de volta para casa, uma mulher se vê presa numa situação perigosa em um ponto de ônibus. O aparente beco sem saída chama a atenção de uma palhaça misteriosa, que decide intervir à própria maneira.', NULL, NULL, CURRENT_TIMESTAMP, 1609770, '/hKgJhSys6nq0pAKW9sb2YR8hEpJ.jpg'),
('1a89c54a-49cd-4258-875b-aba6b31ccc8b', 'Hotel Papucaia', 'Hotel Papucaia', 2026, 'BR', 'pt', NULL, 'Lucas e Brian estão procurando um hotel chamado Hotel Papucaia, mas as coisas não vão totalmente como eles esperavam.', NULL, NULL, CURRENT_TIMESTAMP, 1515862, '/oCmiN4MyvuRTkQdZ9Mh3vOumjfT.jpg'),
('e7e8ef7b-78c5-42ff-92eb-3cf5fd5841dc', 'Av. São João, 588', 'Av. São João, 588', 2026, 'BR', 'pt', NULL, 'Nenhuma mulher sem casa." A frase que guia a luta de Antônia Nascimento ecoa pelos corredores de um edifício que, antes abandonado, hoje se tornou um símbolo de resistência. Coordenadora da Frente de Luta por Moradia (FLM) e ativista há mais de 25 anos, Antônia lidera a transformação de prédios ociosos, sem função social, em lares. “Av. São João, 588” narra, sob sua perspectiva, a luta das mulheres pelo direito a uma moradia digna em São Paulo, revelando os desafios, a força e a esperança de quem, com coragem e união, transforma concreto em lar e pertencimento.', NULL, NULL, CURRENT_TIMESTAMP, 1634351, '/mToWz6Eu3g14YhojHsshV5A1dEF.jpg'),
('72821b46-4453-461b-81e1-8fbba24d4d31', 'Matches', 'Matches', 2026, 'BR', 'en', NULL, '', NULL, NULL, CURRENT_TIMESTAMP, 1610797, '/nuuTePyCkFlbuz8LDRrjBcMrDz4.jpg'),
('94a0840b-5751-4313-9249-015d84645769', 'Os Espelhos de Agnès', 'Os Espelhos de Agnès', 2026, 'BR', 'pt', NULL, '', NULL, NULL, CURRENT_TIMESTAMP, 1611909, '/38GLsBnopP44HFLFQVuY7R5y3Vq.jpg'),
('3bb6a154-d1a7-4a10-922e-28754c8c7583', 'Meu Mal', 'Meu Mal', 2026, 'BR', 'pt', NULL, '', NULL, NULL, CURRENT_TIMESTAMP, 1611830, '/hPZJTtty2Diyq9Xq3zXwUhgNvAj.jpg'),
('fdb0a013-f6b2-4dd3-8275-058d3928d229', 'Memorial', 'Memorial', 2026, 'BR', 'pt', NULL, 'A noite e as estrelas no céu', NULL, NULL, CURRENT_TIMESTAMP, 1611800, '/19TwxfZaw5LfWxiH5Ayt6z2Pyoc.jpg'),
('3da5c5d9-b72c-447c-9039-f6324b4276a4', 'Universidade Federal do Ceará - 70 Anos', 'Universidade Federal do Ceará - 70 Anos', 2026, 'BR', 'pt', NULL, 'O documentário apresenta a trajetória da Universidade Federal do Ceará, sétima universidade pública de ensino superior criada no Brasil e a grande pioneira no estado do Ceará. Celebra o marco dos seus 70 anos de existência e evidencia sua imensurável e extensa contribuição social, intelectual, econômica e cultural, apresentando ao grande público suas histórias, personalidades, feitos e contribuições.', NULL, NULL, CURRENT_TIMESTAMP, 1611613, NULL),
('8946dbc6-8975-4354-a4b6-8beec0f75339', 'The Ascension of the Cicada', 'A Ascensão da Cigarra', 2026, 'BR', 'pt', NULL, 'Quando a noite acende as cigarras, no meio da Amazônia, uma jovem que vive de escrever para funerárias tenta alinhar o corpo e as próprias memórias. //  When night falls and the cicadas chime in the heart of the Amazon, a young woman who makes a living writing for funeral homes tries to reconcile her body with her own memories.', NULL, NULL, CURRENT_TIMESTAMP, 1612740, '/i0PFsk0kerbDIvdIOdQc9OO7gmG.jpg'),
('69ea10d7-1a10-4456-ba9b-0a5d64ab5df0', 'Timidez', 'Timidez', 2026, 'BR', 'pt', NULL, 'Jonas é um jovem artista negro que vive à sombra de Nestor, seu irmão autoritário — uma presença sufocante com quem divide a casa e os silêncios. Mas quando Lúcia, a vizinha do andar de cima, aceita um convite para jantar, Jonas precisará enfrentar seus próprios fantasmas, e começa a duvidar de si mesmo.', NULL, NULL, CURRENT_TIMESTAMP, 1540992, '/12CZ33wR8ci8OxYpgLaYJZ3DwC1.jpg'),
('d44b297a-4516-47fd-88f7-522fd4ddd0c6', 'Agentes Muito Especiais', 'Agentes Muito Especiais', 2026, 'BR', 'pt', NULL, 'Os agentes Jeff e Johnny começam a trabalhar juntos trocando farpas e aos poucos consolidam uma parceria profissional e pessoal. Encarando percalços, perigos e aventuras, os dois se infiltram numa penitenciária para desbaratar uma poderosa quadrilha chefiada pela misteriosa Onça.', NULL, NULL, CURRENT_TIMESTAMP, 1296682, '/lOnODWkmfV3PQDsBYrAdoL2SBT0.jpg'),
('482ae01d-b531-4394-bfc2-abb8e09deb01', 'The Life Aquatic: A Tribute to David Bowie by Seu Jorge', 'The Life Aquatic: A Tribute to David Bowie by Seu Jorge', 2026, 'BR', 'pt', NULL, '', NULL, NULL, CURRENT_TIMESTAMP, 1641943, '/yenfEMNXuPmGwhed5O2NNN3Mzpg.jpg'),
('ed12ec13-f905-4327-b2bb-74755bd8fdf9', 'Climas Artificiais', 'Artificial Climates', 2026, 'BR', 'pt', NULL, 'Este documentário relata os impactos do uso excessivo da Inteligência Artificial nas mudanças climáticas.', NULL, NULL, CURRENT_TIMESTAMP, 1626000, '/40EEHe49cgJSUasdp9Vd2sKxF2I.jpg'),
('db493874-a7ae-4729-b8f2-1505c2604369', 'Orquestra à Base de Sopro Convida Grupo Fato', 'Orquestra à Base de Sopro Convida Grupo Fato', 2026, 'BR', 'pt', NULL, 'Um encontro histórico e inédito. A OABS convidou o Grupo FATO ao palco do Guairinha para celebrar seus 30 anos de trajetória. Reconhecido por suas colaborações com poetas e compositores de destaque, o Grupo FATO é uma referência na fusão de elementos musicais diversos. Este encontro, carregado de simbolismo, remete á criação do Conservatório de MPB de Curitiba e às Oficinas de Música, instituições que moldaram as trajetórias desses dois grupos, "nascidos" na mesma época.', NULL, NULL, CURRENT_TIMESTAMP, 1614011, '/5ExJ3jiKgMLpmixn2vWgNSfkosj.jpg'),
('b0ac9526-a749-4a4d-b03a-c7b78be49e3f', 'Como nasce um BBB', 'Como nasce um BBB', 2026, 'BR', 'pt', NULL, 'Cem mil se inscrevem. Poucos chegam lá. Documentário mostra os bastidores do maior reality show do Brasil, desde a seleção dos participantes até os preparativos para as provas de resistência.', NULL, NULL, CURRENT_TIMESTAMP, 1616423, '/krqxyhjCCoAIZMVnclTICKTJCg9.jpg'),
('4248455e-3310-4656-92b8-0440c774070f', 'Gravação Maldita', 'Gravação Maldita', 2026, 'BR', 'pt', NULL, 'Em um dia de gravação qualquer, de um filme diretamente feito em um dos grandes estúdios de Hollywood, três mulheres são perseguidas por um homem mascarado, que não tem aparência revelada, até então.', NULL, NULL, CURRENT_TIMESTAMP, 1614349, '/ejKX1EZ0mcZUIFGtTocvH3jb8cz.jpg'),
('23ca8ca2-a146-4ef7-b404-cb990aff07ae', 'A Pisadeira', 'A Pisadeira', 2026, 'BR', 'pt', NULL, '', NULL, NULL, CURRENT_TIMESTAMP, 1614200, '/2eliJSKIiRRIo5ugnIYKve6HiWn.jpg'),
('56bfa005-7052-401d-8a6b-4455c744b7dd', 'Conversas nas zonas azuis', 'Conversas nas zonas azuis', 2026, 'BR', 'pt', NULL, 'Documentário que busca semelhanças entre as áreas azuis de várias partes do mundo, como na cidade de Veranópolis, Rio Grande do Sul, Brasil. Zonas azuis são cidades que tem alto índice de centenários.', NULL, NULL, CURRENT_TIMESTAMP, 1621871, NULL),
('303c2946-b3f9-413e-b3c4-a56e80c1a2b3', 'Personalidades Barreirenses: Jango Biriva, Leonora Kolling e João da Macena - Historiando em Novo Barreiro', 'Personalidades Barreirenses: Jango Biriva, Leonora Kolling e João da Macena - Historiando em Novo Barreiro', 2026, 'BR', 'pt', NULL, 'Episódio final da série Historiando é dedicado a registrar e preservar a memória de figuras marcantes da história de Novo Barreiro (RS). O episódio apresenta as trajetórias de Jango Biriva, Leonora Rondani Kolling e João da Macena, reunindo relatos e contextos que ajudam a compreender a formação cultural e social do município.', NULL, NULL, CURRENT_TIMESTAMP, 1620607, '/epEmiho7KYyawH2q37T2gYe6Ii4.jpg'),
('4760da29-3ac8-4475-b7a7-49190cb5fe46', 'Drácula/Homem-Morcego', 'Drácula/Homem-Morcego', 2026, 'BR', 'pt', NULL, 'Em São Paulo o Homem-Morcego investiga estranhos assassinatos.', NULL, NULL, CURRENT_TIMESTAMP, 1617342, '/t94S7rSPefcwyrpDFxaXv79fnVF.jpg'),
('23097f8c-e94e-4fb6-b022-6a37c0b21169', 'Um Corpo Inconveniente', 'Um Corpo Inconveniente', 2026, 'BR', 'pt', NULL, 'Um matador de aluguel pede a ajuda de um amigo ex-matador para se livrar de um corpo. Mas será que ele pode confiar na nova namorada do amigo?', NULL, NULL, CURRENT_TIMESTAMP, 1616544, '/oGMAEO9aTTRml3dMuolSoJU3xSr.jpg'),
('32fcb1c8-dc3c-4a82-9a01-45072ebe64d3', 'Corrida das Blogueiras 7: Final', 'Corrida das Blogueiras 7: Final', 2026, 'BR', 'pt', NULL, 'Depois de uma temporada incrível com recordes de audiência e um elenco que se entregou de corpo e alma, vamos encerrar a Corrida das Blogueiras 7 com chave de ouro AO VIVO na Vibra São Paulo.', NULL, NULL, CURRENT_TIMESTAMP, 1615783, '/ydGSqDwUqMBSFQnxJFzZhB6s36C.jpg'),
('d4b2b760-7756-47e3-8363-2f736af8f417', 'Gameleira Agulha', 'Gameleira Agulha', 2026, 'BR', 'pt', NULL, 'Cobra pariu tempestade defronte buritizal quente. Cachos crônicos, gelei.', NULL, NULL, CURRENT_TIMESTAMP, 1619530, '/mwqElcc1ja29SEl4B7H4epRoqu1.jpg'),
('77be9048-5024-4491-940e-7dd1558e29b3', 'Roda da Vida', 'Roda da Vida', 2026, 'BR', 'pt', NULL, 'Na infância, Lucas e Rafael eram inseparáveis, mas o tempo e as escolhas os levaram por caminhos opostos. Anos depois, um reencontro ao entardecer reacende a possibilidade de mudança, mostrando que a capoeira pode ser um recomeço — mesmo quando tudo parece perdido.', NULL, NULL, CURRENT_TIMESTAMP, 1616536, '/4MB2wbcsZuebIRFfUSbOlaY0qhQ.jpg'),
('87634534-afd6-43c8-b593-79c852216400', 'O Grande Banquete - Ao Vivo em João Pessoa', 'O Grande Banquete - Ao Vivo em João Pessoa', 2026, 'BR', 'pt', NULL, 'A música conduz um percurso de escuta, presença e partilha. Um banquete simbólico onde histórias se cruzam, o tempo desacelera e o encontro com o outro e com o divino se torna o verdadeiro acontecimento.', NULL, NULL, CURRENT_TIMESTAMP, 1611697, '/wfTvhseSowM115zAI9fXtTTOGYI.jpg'),
('a96bac40-ae88-44a3-bc48-de000685373e', 'Ato Noturno', 'Ato Noturno', 2026, 'BR', 'pt', NULL, 'Um ator e um político vivem um caso em sigilo e, juntos, descobrem ter fetiche por sexo em lugares públicos. À medida que se aproximam do sonho da fama, mais intenso se torna o desejo de se colocarem em risco.', NULL, NULL, CURRENT_TIMESTAMP, 1403903, '/o0uHoWYGsZaGSC6O9iTRy4sAz5J.jpg'),
('18c70904-e2eb-4b6c-83c8-82e049e13260', 'O Diário de Pilar na Amazônia', 'O Diário de Pilar na Amazônia', 2026, 'BR', 'pt', NULL, 'Pilar, uma jovem curiosa e exploradora, embarca com o melhor amigo Breno e o gato Samba numa missão na floresta amazônica. Lá, eles conhecem Maiara, uma jovem ribeirinha cuja comunidade foi destruída por madeireiros. No caminho, encontram Bira, um jovem pescador que conhece bem a floresta. Pilar e seus amigos partem em busca dos pais de Maiara, até que descobrem uma quadrilha de madeireiros que estão cortando árvores ilegalmente. Com a ajuda de uma tribo indígena e dos seres mitológicos, Pilar e seus amigos conseguem deter os madeireiros, mais decididos que nunca a salvar a natureza e a reflorestar o planeta.', NULL, NULL, CURRENT_TIMESTAMP, 1135423, '/kFBWjlAhdGgVFYXFN6hI5Pflezy.jpg'),
('ba2a71e1-64cf-40f2-b5b4-bb1bb13b66df', 'Em Trans(e)', 'Em Trans(e)', 2026, 'BR', 'pt', NULL, 'Produzido por um coletivo de 5 pessoas trans, Em Trans(e) aborda a importância de "transcentrar" (relacionar-se afetiva e/ou amorosamente com outras pessoas trans) na vida da caloura Ângela, que acaba de iniciar sua transição de gênero.  Em sua jornada, conhece Jonas, um transmasculino seguro de si, que ajuda Ângela a ter autoconfiança para enfrentar o mundo e principalmente sua família.', NULL, NULL, CURRENT_TIMESTAMP, 1646979, '/laIAW5mxbrHfStG5pmWC3mgDA30.jpg'),
('6ad62701-ad05-4109-b92c-e6b238221293', 'Lua de Sangue 3: O Último Capítulo', 'Lua de Sangue 3: O Último Capítulo', 2026, 'BR', 'pt', NULL, '', NULL, NULL, CURRENT_TIMESTAMP, 1620311, '/zxlfX9gVK37enFA1LgWCLvlphd2.jpg'),
